SELECT name, value, isdefault
FROM V$PARAMETER
WHERE name = 'temp_undo_enabled';

-- 세션 레벨 활성화
ALTER SESSION SET TEMP_UNDO_ENABLED = TRUE;

-- 시스템 레벨 활성화
ALTER SYSTEM SET TEMP_UNDO_ENABLED = TRUE SCOPE=BOTH;

-- Global Temporary Table 생성
CREATE GLOBAL TEMPORARY TABLE gtt_test (
  id    NUMBER,
  data  VARCHAR2(100)
) ON COMMIT PRESERVE ROWS;

-- Temporary UNDO 활성화
ALTER SESSION SET TEMP_UNDO_ENABLED = TRUE;

-- GTT에 데이터 삽입 (Temp UNDO 사용)
INSERT INTO gtt_test
SELECT level, 'test data ' || level
FROM dual CONNECT BY level <= 10000;

-- Temp UNDO 사용 확인
SELECT undoblks, txncount
FROM V$TEMPUNDOSTAT
WHERE begin_time = (SELECT MAX(begin_time) FROM V$TEMPUNDOSTAT);

-- 1. 현재 모드 확인
SELECT property_value FROM DATABASE_PROPERTIES
WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- 2. CDB 종료
SHUTDOWN IMMEDIATE;

-- 3. UPGRADE 모드로 시작
STARTUP UPGRADE;

-- 4. Local UNDO 활성화
ALTER DATABASE LOCAL UNDO ON;

-- 5. 모든 PDB UPGRADE 모드 OPEN
ALTER PLUGGABLE DATABASE ALL OPEN UPGRADE;

-- 6. CDB 재시작
SHUTDOWN IMMEDIATE;
STARTUP;

-- 7. 모든 PDB OPEN
ALTER PLUGGABLE DATABASE ALL OPEN;

-- 8. 전환 확인
SELECT property_value FROM DATABASE_PROPERTIES
WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- 1. 현재 모드 확인
SELECT property_value FROM DATABASE_PROPERTIES
WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- 2. CDB 종료
SHUTDOWN IMMEDIATE;

-- 3. UPGRADE 모드로 시작
STARTUP UPGRADE;

-- 4. Local UNDO 비활성화
ALTER DATABASE LOCAL UNDO OFF;

-- 5. CDB 재시작
SHUTDOWN IMMEDIATE;
STARTUP;

-- 6. 모든 PDB OPEN
ALTER PLUGGABLE DATABASE ALL OPEN;

-- 7. 전환 확인
SELECT property_value FROM DATABASE_PROPERTIES
WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- PDB에 접속
ALTER SESSION SET CONTAINER = pdb1;

-- 새 UNDO 테이블스페이스 생성
CREATE UNDO TABLESPACE undotbs_pdb1_new
  DATAFILE '/u01/app/oracle/oradata/cdb1/pdb1/undotbs_pdb1_new_01.dbf'
  SIZE 500M AUTOEXTEND ON NEXT 100M MAXSIZE 5G;

-- UNDO 테이블스페이스 전환
ALTER SYSTEM SET UNDO_TABLESPACE = 'UNDOTBS_PDB1_NEW' SCOPE=BOTH;

-- 이전 UNDO 테이블스페이스의 세그먼트가 모두 OFFLINE 될 때까지 대기 후 삭제
-- (활성 트랜잭션 완료 후)
DROP TABLESPACE undotbs_pdb1_old INCLUDING CONTENTS AND DATAFILES;

-- PDB1에 접속하여 UNDO_RETENTION 설정
ALTER SESSION SET CONTAINER = pdb1;
ALTER SYSTEM SET UNDO_RETENTION = 1800 SCOPE=BOTH;

-- PDB2에 접속하여 다른 UNDO_RETENTION 설정
ALTER SESSION SET CONTAINER = pdb2;
ALTER SYSTEM SET UNDO_RETENTION = 600 SCOPE=BOTH;

-- 각 PDB의 UNDO_RETENTION 확인
SELECT con_id, name, value
FROM V$SYSTEM_PARAMETER
WHERE name = 'undo_retention';
